parts.algorithm:
# during top-k pick:
for each token:
    selected = []
    groups_used = set()
    for e in sorted_by_score:
        if len(groups_used) >= 4 and group(e) not in groups_used:
            continue
        selected.append(e)
        groups_used.add(group(e))
        if len(selected) == 8: break

for e in topk_idx:
    h_e = silu(x @ W_gate[e]) * (x @ W_up[e])
    y  += w_topk * (h_e @ W_down[e])

if mode == 'think':
    prompt = THINKING_TEMPLATE + user
    decode_budget = 8192   # CoT tokens
else:
    prompt = STD_TEMPLATE + user
    decode_budget = 1024
